1	import type { Express, Request, Response } from "express";
2	import { Router } from "express";
3	import { v4 as uuid } from "uuid";
4	import { findAll, findBy, findById, insert, update } from "../../db.js";
5	import { authorize, getCurrentUser, requireLogin } from "../../shared/auth.js";
6	
7	const PROJECTION_TYPES = [
8	  "race_progress",
9	  "registration_status",
10	  "cost",
11	  "risk",
12	  "submission",
13	  "judging",
14	  "current_leaderboard",
15	  "screen_feed",
16	] as const;
17	
18	type ProjectionType = typeof PROJECTION_TYPES[number];
19	type ReadModelType = "leaderboard_read_model" | "results_page_read_model" | "review_summary_read_model";
20	type ReadMode = "live" | "stable_fallback" | "static_fallback";
21	type FallbackCode = "none" | "projection_failed_uses_stable" | "projection_failed_uses_static";
22	type StatusReadMode = ReadMode | "not_built";
23	type ServeReadiness = "live" | "degraded" | "partial" | "not_ready";
24	
25	interface ContractDescriptor {
26	  readKind: "projection" | "read_model";
27	  sourceOfTruth: string[];
28	  consumerBoundary: string;
29	}
30	
31	interface Race {
32	  id: string;
33	  slug: string;
34	  title: string;
35	  challenge: string;
36	  status: string;
37	  visibility: string;
38	  organizer_user_ids: string[] | string;
39	  registration_opens_at: string | null;
40	  registration_closes_at: string | null;
41	  starts_at: string | null;
42	  ends_at: string | null;
43	  created_at: string;
44	  updated_at: string;
45	}
46	
47	interface Registration {
48	  id: string;
49	  race_id: string;
50	  user_id: string;
51	  status: string;
52	  submitted_at: string;
53	  approved_at: string | null;
54	  rejected_at: string | null;
55	  withdrawn_at: string | null;
56	  created_at: string;
57	  updated_at: string;
58	}
59	
60	interface RaceProject {
61	  id: string;
62	  registration_id: string;
63	  race_id: string;
64	  user_id: string;
65	  aggregate_ingestion_status: string;
66	  connection_health: string;
67	  last_synced_at: string | null;
68	  created_at: string;
69	  updated_at: string;
70	}
71	
72	interface CAConnection {
73	  id: string;
74	  race_project_id: string;
75	  connector_id: string;
76	  handshake_status: string;
77	  ingestion_status: string;
78	  disabled_at: string | null;
79	  last_synced_at: string | null;
80	  created_at: string;
81	  updated_at: string;
82	}
83	
84	interface SessionRow {
85	  id: string;
86	  ca_connection_id: string;
87	  race_project_id: string;
88	  message_count: number;
89	  tool_call_count: number;
90	  token_cost: number;
91	  accepted_at: string;
92	  created_at: string;
93	}
94	
95	interface Work {
96	  id: string;
97	  registration_id: string;
98	  race_id: string;
99	  user_id: string;
100	  slug: string;
101	  title: string;
102	  summary: string;
103	  status: string;
104	  visibility: string;
105	  submitted_at: string | null;
106	  published_at: string | null;
107	  created_at: string;
108	  updated_at: string;
109	}
110	
111	interface JudgeAssignment {
112	  id: string;
113	  work_id: string;
114	  judge_user_id: string;
115	  assigned_by_user_id: string;
116	  assigned_at: string;
117	  created_at: string;
118	  updated_at: string;
119	}
120	
121	interface JudgingRecord {
122	  id: string;
123	  judge_assignment_id: string;
124	  score_result: number | null;
125	  score_riding: number | null;
126	  comments: string;
127	  status: "draft" | "submitted";
128	  submitted_at: string | null;
129	  created_at: string;
130	  updated_at: string;
131	}
132	
133	interface Award {
134	  id: string;
135	  race_id: string;
136	  registration_id: string;
137	  work_id: string | null;
138	  award_name: string;
139	  rank: number;
140	  decision_reason: string;
141	  status: "draft" | "published";
142	  visibility: string;
143	  published_at: string | null;
144	  created_at: string;
145	  updated_at: string;
146	}
147	
148	interface Announcement {
149	  id: string;
150	  race_id: string;
151	  title: string;
152	  body: string;
153	  visibility: string;
154	  published_at: string | null;
155	  created_at: string;
156	}
157	
158	interface UserRow {
159	  id: string;
160	  githubAccount?: string;
161	  github_account?: string;
162	  displayName?: string;
163	  display_name?: string;
164	}
165	
166	interface ReportRow {
167	  id: string;
168	  race_id: string;
169	  report_type: "rider_report" | "race_report" | "review_summary";
170	  title?: string;
171	  summary?: string;
172	  body_markdown?: string;
173	  visibility?: string;
174	  status?: string;
175	  published_at?: string | null;
176	  updated_at?: string;
177	  created_at?: string;
178	}
179	
180	interface ProjectionRow {
181	  id: string;
182	  race_id: string;
183	  type: ProjectionType;
184	  status: "ready" | "failed";
185	  data: unknown;
186	  generated_at: string | null;
187	  last_attempted_at: string;
188	  last_error: string | null;
189	  created_at: string;
190	  updated_at: string;
191	}
192	
193	interface ProjectionReadResult {
194	  row: ProjectionRow;
195	  mode: ReadMode;
196	  fallbackReason: string | null;
197	}
198	
199	interface ScreenFeedItem<T = unknown> {
200	  id: string;
201	  feedItemType: "live_metrics" | "process_leaderboard" | "final_leaderboard" | "work_highlight" | "announcement";
202	  mode: "live" | "leaderboard" | "works" | "announcement";
203	  title: string;
204	  order: number;
205	  durationMs: number;
206	  recommendedDisplayMode: "live" | "leaderboard" | "works" | "announcement";
207	  fallbackPriority: 1 | 2 | 3 | 4;
208	  data: T;
209	}
210	
211	interface ProjectionContext {
212	  race: Race;
213	  registrations: Registration[];
214	  raceProjects: RaceProject[];
215	  caConnections: CAConnection[];
216	  sessions: SessionRow[];
217	  works: Work[];
218	  judgeAssignments: JudgeAssignment[];
219	  judgingRecords: JudgingRecord[];
220	  awards: Award[];
221	  announcements: Announcement[];
222	  users: UserRow[];
223	  reports: ReportRow[];
224	}
225	
226	const CONTRACT_VERSION = "d.v1";
227	const PROJECTION_DESCRIPTORS: Record<ProjectionType, ContractDescriptor> = {
228	  race_progress: { readKind: "projection", sourceOfTruth: ["races", "registrations", "race_projects", "sessions", "works", "awards", "announcements"], consumerBoundary: "Live Hall / process display only" },
229	  registration_status: { readKind: "projection", sourceOfTruth: ["registrations", "race_projects", "works", "sessions", "users"], consumerBoundary: "Live Hall / Console status only" },
230	  cost: { readKind: "projection", sourceOfTruth: ["registrations", "race_projects", "sessions"], consumerBoundary: "Process metrics only" },
231	  risk: { readKind: "projection", sourceOfTruth: ["race_projects", "registrations", "works"], consumerBoundary: "Risk display only" },
232	  submission: { readKind: "projection", sourceOfTruth: ["works"], consumerBoundary: "Submission state only" },
233	  judging: { readKind: "projection", sourceOfTruth: ["judge_assignments", "judging_records", "works"], consumerBoundary: "Judging progress only" },
234	  current_leaderboard: { readKind: "projection", sourceOfTruth: ["registrations", "works", "race_projects", "judge_assignments", "judging_records", "sessions"], consumerBoundary: "Process leaderboard only; never final result" },
235	  screen_feed: { readKind: "projection", sourceOfTruth: ["race_progress", "current_leaderboard", "leaderboard_read_model", "works", "announcements"], consumerBoundary: "Screen display feed only" },
236	};
237	
238	const READ_MODEL_DESCRIPTORS: Record<ReadModelType, ContractDescriptor> = {
239	  leaderboard_read_model: { readKind: "read_model", sourceOfTruth: ["awards"], consumerBoundary: "Final published leaderboard only" },
240	  results_page_read_model: { readKind: "read_model", sourceOfTruth: ["awards", "works", "reports"], consumerBoundary: "Public Results page only; excludes process leaderboard" },
241	  review_summary_read_model: { readKind: "read_model", sourceOfTruth: ["reports", "awards", "works"], consumerBoundary: "Public Review page only; excludes process projection as final fact" },
242	};
243	
244	export function registerProjectionRoutes(app: Express): void {
245	  const router = Router();
246	
247	  router.get("/:raceId/status-summary", requireLogin, (req: Request, res: Response) => {
248	    const race = resolveRace(req.params.raceId);
249	    if (!race) {
250	      res.status(404).json({ error: "Race not found" });
251	      return;
252	    }
253	
254	    const user = getCurrentUser(req);
255	    const auth = authorize(user, "Projection", "inspect_status", {
256	      raceOrganizerIds: parseStringArray(race.organizer_user_ids),
257	    });
258	    if (!auth.allowed) {
259	      res.status(403).json({ error: auth.reason });
260	      return;
261	    }
262	
263	    const context = buildContext(race);
264	    const projections = PROJECTION_TYPES.map((type) => inspectProjectionStatus(race, type));
265	    const readModels = (["leaderboard_read_model", "results_page_read_model", "review_summary_read_model"] as ReadModelType[])
266	      .map((type) => inspectReadModelStatus(race, context, type));
267	    const statusSummary = buildProjectionStatusSummary(race, projections, readModels);
268	
269	    res.json({
270	      contractVersion: CONTRACT_VERSION,
271	      race: toRaceSummary(race),
272	      summary: statusSummary,
273	      projections,
274	      readModels,
275	    });
276	  });
277	
278	  router.get("/:raceId/:type", (req: Request, res: Response) => {
279	    const race = resolveRace(req.params.raceId);
280	    if (!race) {
281	      res.status(404).json({ error: "Race not found" });
282	      return;
283	    }
284	
285	    const user = getCurrentUser(req);
286	    const auth = canReadProjection(user, race);
287	    if (!auth.allowed) {
288	      res.status(403).json({ error: auth.reason });
289	      return;
290	    }
291	
292	    const type = req.params.type;
293	    if (type === "leaderboard_read_model") {
294	      const data = buildLeaderboardReadModel(buildContext(race));
295	      res.json(toReadModelResponse(race.id, type, newestTimestamp(data.groups.flatMap((group) => group.items.map((item) => item.publishedAt)).filter(Boolean as any)) || new Date().toISOString(), data));
296	      return;
297	    }
298	    if (type === "results_page_read_model") {
299	      const data = buildResultsPageReadModel(buildContext(race));
300	      res.json(toReadModelResponse(race.id, type, newestTimestamp([
301	          data.review.report?.publishedAt || "",
302	          ...data.leaderboard.groups.flatMap((group) => group.items.map((item) => item.publishedAt || "")),
303	          ...data.winningWorks.map((work) => work.publishedAt || ""),
304	        ].filter(Boolean)) || new Date().toISOString(), data));
305	      return;
306	    }
307	    if (type === "review_summary_read_model") {
308	      const data = buildReviewSummaryReadModel(buildContext(race));
309	      res.json(toReadModelResponse(race.id, type, data.report.report?.publishedAt || newestTimestamp(data.winningWorks.map((work) => work.publishedAt || "").filter(Boolean)) || new Date().toISOString(), data));
310	      return;
311	    }
312	
313	    if (!isProjectionType(type)) {
314	      res.status(400).json({ error: "Unsupported projection type" });
315	      return;
316	    }
317	
318	    try {
319	      const projection = readProjection(race, type);
320	      res.json(toProjectionResponse(projection));
321	    } catch (error) {
322	      res.status(503).json({ error: error instanceof Error ? error.message : "Projection unavailable" });
323	    }
324	  });
325	
326	  router.post("/:raceId/rebuild", requireLogin, (req: Request, res: Response) => {
327	    const race = resolveRace(req.params.raceId);
328	    if (!race) {
329	      res.status(404).json({ error: "Race not found" });
330	      return;
331	    }
332	
333	    const user = getCurrentUser(req);
334	    const auth = authorize(user, "Projection", "rebuild", {
335	      raceOrganizerIds: parseStringArray(race.organizer_user_ids),
336	    });
337	    if (!auth.allowed) {
338	      res.status(403).json({ error: auth.reason });
339	      return;
340	    }
341	
342	    const rebuiltAt = new Date().toISOString();
343	    const results = PROJECTION_TYPES.map((type) => {
344	      try {
345	        const row = rebuildProjection(race, type, rebuiltAt);
346	        return toProjectionResponse({ row, mode: "live", fallbackReason: null });
347	      } catch (error) {
348	        const row = markProjectionFailed(race.id, type, error instanceof Error ? error.message : "Projection rebuild failed", rebuiltAt);
349	        return toProjectionResponse({
350	          row,
351	          mode: row.generated_at ? "stable_fallback" : "live",
352	          fallbackReason: row.generated_at ? (row.last_error || "Projection rebuild failed") : null,
353	        });
354	      }
355	    });
356	
357	    res.json({
358	      raceId: race.id,
359	      rebuiltAt,
360	      summary: {
361	        ready: results.filter((result) => result.status === "ready").length,
362	        failed: results.filter((result) => result.status === "failed").length,
363	        usingStableFallback: results.filter((result) => result.readMode === "stable_fallback").length,
364	      },
365	      projections: results,
366	    });
367	  });
368	
369	  app.use("/projections", router);
370	  console.log("[projection] Routes registered: /projections/*");
371	}
372	
373	function canReadProjection(user: ReturnType<typeof getCurrentUser>, race: Race) {
374	  const publicAuth = authorize(user, "Projection", "view_public", {
375	    visibility: race.visibility,
376	    isPublished: race.visibility === "public",
377	  });
378	  if (publicAuth.allowed) return publicAuth;
379	  return authorize(user, "Projection", "view_internal", {
380	    raceOrganizerIds: parseStringArray(race.organizer_user_ids),
381	  });
382	}
383	
384	function getOrBuildProjection(race: Race, type: ProjectionType): ProjectionRow {
385	  const existing = findProjection(race.id, type);
386	  if (existing) return existing;
387	  return rebuildProjection(race, type);
388	}
389	
390	function readProjection(race: Race, type: ProjectionType): ProjectionReadResult {
391	  const projection = getOrBuildProjection(race, type);
392	  if (projection.status === "ready") {
393	    return { row: projection, mode: "live", fallbackReason: null };
394	  }
395	  if (projection.generated_at) {
396	    return {
397	      row: projection,
398	      mode: "stable_fallback",
399	      fallbackReason: projection.last_error || "Projection unavailable, using last stable snapshot.",
400	    };
401	  }
402	  return {
403	    row: buildStaticFallbackRow(race, type, projection.last_error || "Projection unavailable"),
404	    mode: "static_fallback",
405	    fallbackReason: projection.last_error || "Projection unavailable, using static fallback.",
406	  };
407	}
408	
409	function rebuildProjection(race: Race, type: ProjectionType, timestamp = new Date().toISOString()): ProjectionRow {
410	  const context = buildContext(race);
411	  const data = buildProjectionData(type, context);
412	  return upsertProjection(race.id, type, data, timestamp);
413	}
414	
415	function buildProjectionData(type: ProjectionType, context: ProjectionContext) {
416	  if (type === "race_progress") return buildRaceProgress(context);
417	  if (type === "registration_status") return buildRegistrationStatus(context);
418	  if (type === "cost") return buildCostProjection(context);
419	  if (type === "risk") return buildRiskProjection(context);
420	  if (type === "submission") return buildSubmissionProjection(context);
421	  if (type === "judging") return buildJudgingProjection(context);
422	  if (type === "current_leaderboard") return buildCurrentLeaderboardProjection(context);
423	  return buildScreenFeedProjection(context);
424	}
425	
426	function buildContext(race: Race): ProjectionContext {
427	  return {
428	    race,
429	    registrations: findAll<Registration>("registrations").filter((row) => row.race_id === race.id),
430	    raceProjects: findAll<RaceProject>("race_projects").filter((row) => row.race_id === race.id),
431	    caConnections: findAll<CAConnection>("ca_connections"),
432	    sessions: findAll<SessionRow>("sessions"),
433	    works: findAll<Work>("works").filter((row) => row.race_id === race.id),
434	    judgeAssignments: findAll<JudgeAssignment>("judge_assignments"),
435	    judgingRecords: findAll<JudgingRecord>("judging_records"),
436	    awards: findAll<Award>("awards").filter((row) => row.race_id === race.id),
437	    announcements: findAll<Announcement>("announcements").filter((row) => row.race_id === race.id),
438	    users: findAll<UserRow>("users"),
439	    reports: findAll<ReportRow>("reports").filter((row) => row.race_id === race.id),
440	  };
441	}
442	
443	function buildRaceProgress(context: ProjectionContext) {
444	  const metrics = summarizeMetrics(context);
445	  const eventStream = buildEventStream(context);
446	  const publishedAwards = context.awards.filter((award) => award.status === "published" && award.visibility === "public");
447	
448	  return {
449	    race: toRaceSummary(context.race),
450	    stageLabel: formatRaceStage(context.race.status),
451	    headline: buildRaceHeadline(context.race.status, metrics),
452	    counts: {
453	      registrationsTotal: context.registrations.length,
454	      approvedRegistrations: context.registrations.filter((row) => row.status === "approved").length,
455	      worksSubmitted: context.works.filter((row) => row.status === "submitted" || row.status === "locked").length,
456	      worksPublished: context.works.filter((row) => row.visibility === "public" && row.published_at).length,
457	      judgingSubmitted: context.judgingRecords.filter((row) => row.status === "submitted").length,
458	      awardsPublished: publishedAwards.length,
459	      activeConnections: metrics.activeConnections,
460	      sessionCount: metrics.sessionCount,
461	    },
462	    totals: {
463	      tokenCost: metrics.tokenCost,
464	      toolCallCount: metrics.toolCallCount,
465	      messageCount: metrics.messageCount,
466	    },
467	    eventStream,
468	    note: "过程数据仅用于 Live Hall 和大屏展示，不代替最终赛果。",
469	  };
470	}
471	
472	function buildRegistrationStatus(context: ProjectionContext) {
473	  const raceProjectByRegistrationId = new Map(context.raceProjects.map((row) => [row.registration_id, row]));
474	  const workByRegistrationId = new Map(context.works.map((row) => [row.registration_id, row]));
475	  const userById = new Map(context.users.map((row) => [row.id, row]));
476	
477	  const registrations = context.registrations
478	    .slice()
479	    .sort((a, b) => compareTimestamps(b.updated_at, a.updated_at))
480	    .map((registration) => {
481	      const raceProject = raceProjectByRegistrationId.get(registration.id) || null;
482	      const work = workByRegistrationId.get(registration.id) || null;
483	      const metrics = summarizeRegistrationMetrics(context, registration.id, raceProject?.id || null);
484	      const user = userById.get(registration.user_id);
485	      return {
486	        registrationId: registration.id,
487	        userId: registration.user_id,
488	        riderName: readDisplayName(user, registration.user_id),
489	        status: registration.status,
490	        workStatus: work?.status || "not_created",
491	        workTitle: work?.title || null,
492	        raceProjectId: raceProject?.id || null,
493	        aggregateIngestionStatus: raceProject?.aggregate_ingestion_status || "missing",
494	        connectionHealth: raceProject?.connection_health || "unknown",
495	        sessionCount: metrics.sessionCount,
496	        tokenCost: metrics.tokenCost,
497	        toolCallCount: metrics.toolCallCount,
498	        lastSyncedAt: raceProject?.last_synced_at || null,
499	      };
500	    });
501	
502	  return {
503	    race: toRaceSummary(context.race),
504	    registrations,
505	  };
506	}
507	
508	function buildCostProjection(context: ProjectionContext) {
509	  const raceProjectByRegistrationId = new Map(context.raceProjects.map((row) => [row.registration_id, row]));
510	  const totals = summarizeMetrics(context);
511	
512	  const byRegistration = context.registrations.map((registration) => {
513	    const raceProject = raceProjectByRegistrationId.get(registration.id) || null;
514	    const metrics = summarizeRegistrationMetrics(context, registration.id, raceProject?.id || null);
515	    return {
516	      registrationId: registration.id,
517	      userId: registration.user_id,
518	      sessionCount: metrics.sessionCount,
519	      tokenCost: metrics.tokenCost,
520	      toolCallCount: metrics.toolCallCount,
521	      messageCount: metrics.messageCount,
522	    };
523	  });
524	
525	  return {
526	    race: toRaceSummary(context.race),
527	    totals: {
528	      sessionCount: totals.sessionCount,
529	      tokenCost: totals.tokenCost,
530	      toolCallCount: totals.toolCallCount,
531	      messageCount: totals.messageCount,
532	    },
533	    byRegistration,
534	  };
535	}
536	
537	function buildRiskProjection(context: ProjectionContext) {
538	  const workByRegistrationId = new Map(context.works.map((row) => [row.registration_id, row]));
539	  const items: Array<{
540	    code: string;
541	    severity: "warning";
542	    registrationId?: string;
543	    raceProjectId?: string;
544	    title: string;
545	    message: string;
546	  }> = [];
547	
548	  for (const raceProject of context.raceProjects) {
549	    if (raceProject.aggregate_ingestion_status === "failed") {
550	      items.push({
551	        code: "ca_ingestion_failed",
552	        severity: "warning",
553	        registrationId: raceProject.registration_id,
554	        raceProjectId: raceProject.id,
555	        title: "CA 接入失败",
556	        message: `RaceProject ${raceProject.id} 当前为 failed，评审前需要明确告知证据缺口。`,
557	      });
558	    }
559	    if (raceProject.aggregate_ingestion_status === "not_configured") {
560	      items.push({
561	        code: "ca_not_configured",
562	        severity: "warning",
563	        registrationId: raceProject.registration_id,
564	        raceProjectId: raceProject.id,
565	        title: "尚未配置 CA",
566	        message: `RaceProject ${raceProject.id} 尚未接入有效 CAConnection。`,
567	      });
568	    }
569	  }
570	
571	  if (["submitting", "judging", "completed"].includes(context.race.status)) {
572	    for (const registration of context.registrations.filter((row) => row.status === "approved")) {
573	      if (!workByRegistrationId.has(registration.id)) {
574	        items.push({
575	          code: "missing_work",
576	          severity: "warning",
577	          registrationId: registration.id,
578	          title: "缺少作品提交",
579	          message: `报名 ${registration.id} 已通过，但当前阶段尚未看到主 Work。`,
580	        });
581	      }
582	    }
583	  }
584	
585	  return {
586	    race: toRaceSummary(context.race),
587	    counts: {
588	      total: items.length,
589	      caFailed: items.filter((item) => item.code === "ca_ingestion_failed").length,
