661	function buildCurrentLeaderboardProjection(context: ProjectionContext) {
662	  const workByRegistrationId = new Map(context.works.map((row) => [row.registration_id, row]));
663	  const raceProjectByRegistrationId = new Map(context.raceProjects.map((row) => [row.registration_id, row]));
664	  const assignmentByWorkId = new Map<string, JudgeAssignment[]>();
665	  const recordByAssignmentId = new Map(context.judgingRecords.map((row) => [row.judge_assignment_id, row]));
666	
667	  for (const assignment of context.judgeAssignments) {
668	    const current = assignmentByWorkId.get(assignment.work_id) || [];
669	    current.push(assignment);
670	    assignmentByWorkId.set(assignment.work_id, current);
671	  }
672	
673	  const items = context.registrations
674	    .filter((registration) => registration.status === "approved")
675	    .map((registration) => {
676	      const work = workByRegistrationId.get(registration.id) || null;
677	      const raceProject = raceProjectByRegistrationId.get(registration.id) || null;
678	      const metrics = summarizeRegistrationMetrics(context, registration.id, raceProject?.id || null);
679	      const assignments = work ? assignmentByWorkId.get(work.id) || [] : [];
680	      const submittedRecords = assignments
681	        .map((assignment) => recordByAssignmentId.get(assignment.id))
682	        .filter((record): record is JudgingRecord => Boolean(record && record.status === "submitted"));
683	
684	      const reviewAverage = submittedRecords.length === 0
685	        ? 0
686	        : submittedRecords.reduce((sum, record) => sum + Number(record.score_result || 0) + Number(record.score_riding || 0), 0) / (submittedRecords.length * 2);
687	      const processScore = Number((
688	        reviewAverage
689	        + (work?.status === "submitted" || work?.status === "locked" ? 6 : 0)
690	        + (raceProject?.aggregate_ingestion_status === "active" ? 4 : 0)
691	        + Math.min(metrics.sessionCount, 12) * 0.5
692	      ).toFixed(1));
693	
694	      return {
695	        registrationId: registration.id,
696	        userId: registration.user_id,
697	        workId: work?.id || null,
698	        workTitle: work?.title || "待提交作品",
699	        processScore,
700	        reviewAverage: Number(reviewAverage.toFixed(1)),
701	        sessionCount: metrics.sessionCount,
702	        aggregateIngestionStatus: raceProject?.aggregate_ingestion_status || "missing",
703	      };
704	    })
705	    .sort((a, b) => b.processScore - a.processScore || b.reviewAverage - a.reviewAverage || a.registrationId.localeCompare(b.registrationId))
706	    .map((item, index) => ({
707	      rank: index + 1,
708	      ...item,
709	    }));
710	
711	  return {
712	    race: toRaceSummary(context.race),
713	    note: "这是过程榜单，帮助观看正在发生的 Agent Riding，不等同最终 Award。",
714	    items,
715	  };
716	}
