358	export async function requestJson<T>(url: string, init: RequestInit = {}): Promise<T> {
359	  const response = await fetch(url, {
360	    ...init,
361	    headers: init.body ? { "Content-Type": "application/json", ...(init.headers || {}) } : init.headers,
362	    credentials: "include",
363	  });
364	  if (!response.ok) throw new Error(await readErrorMessage(response));
365	  return response.json() as Promise<T>;
366	}
367	
368	export async function readErrorMessage(response: Response) {
369	  let error = "";
370	  try {
371	    const body = await response.json();
372	    error = typeof body.error === "string" ? body.error : "";
373	  } catch {
374	    error = "";
375	  }
376	  if (response.status === 400) return error || "提交内容不符合要求。";
377	  if (response.status === 403) return error || "当前账号没有操作权限。";
378	  if (response.status === 409) return error || "当前数据状态不允许继续操作。";
379	  return error || "请求失败，请稍后重试。";
380	}
