26	export function getCurrentUser(req: Request): AuthUser | null {
27	  const userId = req.session?.userId;
28	  if (!userId) return null;
29	  const row = findById<{ display_name: string; roles: string }>("users", userId);
30	  if (!row) return null;
31	  return {
32	    userId,
33	    displayName: row.display_name,
34	    roles: parseRoles(row.roles),
35	  };
36	}
37	
38	function parseRoles(raw: string | string[]): RoleType[] {
39	  if (Array.isArray(raw)) return raw.filter(r => ["rider","judge","organizer","admin"].includes(r)) as RoleType[];
40	  try { return JSON.parse(raw); } catch { return []; }
41	}
42	
43	export function requireLogin(req: Request, res: Response, next: NextFunction): void {
44	  const user = getCurrentUser(req);
45	  if (!user) { res.status(401).json({ error: "Login required" }); return; }
46	  req.currentUser = user;
47	  next();
48	}
49	
50	export interface ResourceContext {
51	  ownerUserId?: string;
52	  assignedJudgeUserId?: string;
53	  raceOrganizerIds?: string[];
54	  visibility?: string;
55	  isPublished?: boolean;
56	}
57	
58	export function authorize(user: AuthUser | null, resourceType: string, action: string, ctx: ResourceContext = {}): AuthResult {
59	  if (user?.roles.includes("admin")) return { allowed: true };
60	
61	  const scope = getRequiredScope(resourceType, action);
62	
63	  if (scope === "PUBLIC") {
64	    if (ctx.visibility === "public" && ctx.isPublished !== false) return { allowed: true };
65	    return { allowed: false, reason: "Resource is not publicly visible" };
66	  }
67	
68	  if (!user) return { allowed: false, reason: "Login required" };
69	
70	  if (scope === "OWN") {
71	    if (ctx.ownerUserId === user.userId) return { allowed: true };
72	    return { allowed: false, reason: "Not the owner" };
73	  }
74	
75	  if (scope === "ASSIGNED") {
76	    if (ctx.assignedJudgeUserId === user.userId) return { allowed: true };
77	    return { allowed: false, reason: "Not assigned" };
78	  }
79	
80	  if (scope === "MANAGED_RACE") {
81	    if (!user.roles.includes("organizer")) return { allowed: false, reason: "Not an organizer" };
82	    if (ctx.raceOrganizerIds?.includes(user.userId) || !ctx.raceOrganizerIds) return { allowed: true };
83	    return { allowed: false, reason: "Not an organizer of this race" };
84	  }
85	
86	  return { allowed: false, reason: "Insufficient permissions" };
87	}
88	
89	// ── Permission matrix ──
90	type ScopeReq = "PUBLIC" | "OWN" | "ASSIGNED" | "MANAGED_RACE" | "SYSTEM";
91	const MATRIX: Record<string, Record<string, ScopeReq>> = {
92	  Race: { view_public:"PUBLIC", view_private:"MANAGED_RACE", create:"MANAGED_RACE", edit:"MANAGED_RACE", publish:"MANAGED_RACE", archive:"MANAGED_RACE" },
93	  Registration: { submit:"OWN", view:"OWN", approve:"MANAGED_RACE", reject:"MANAGED_RACE", withdraw:"OWN" },
94	  RaceProject: { view_status:"OWN", register_ca_connection:"OWN", manage_ca_connection:"OWN", view_session_summary:"OWN", view_raw_session:"MANAGED_RACE" },
95	  Work: { view_public:"PUBLIC", view_private:"OWN", create:"OWN", submit:"OWN", lock:"MANAGED_RACE", publish:"MANAGED_RACE", hide:"OWN", review:"ASSIGNED" },
96	  Evidence: { view_public:"PUBLIC", view_private_summary:"OWN", set_visibility:"OWN", cite_in_report:"MANAGED_RACE" },
97	  JudgeAssignment: { view:"ASSIGNED", create:"MANAGED_RACE", update:"MANAGED_RACE", remove:"MANAGED_RACE" },
98	  JudgingRecord: { view_published_summary:"PUBLIC", view_private:"OWN", create:"ASSIGNED", submit:"ASSIGNED", update_before_submit:"ASSIGNED" },
99	  Award: { view_published:"PUBLIC", view_draft:"MANAGED_RACE", create_draft:"MANAGED_RACE", edit_draft:"MANAGED_RACE", publish:"MANAGED_RACE", withdraw_publication:"MANAGED_RACE" },
100	  Projection: { view_public:"PUBLIC", view_internal:"MANAGED_RACE", rebuild:"MANAGED_RACE", inspect_status:"MANAGED_RACE" },
101	  Report: { view_public_published:"PUBLIC", view_private:"OWN", generate:"MANAGED_RACE", edit:"MANAGED_RACE", publish:"MANAGED_RACE", regenerate:"MANAGED_RACE" },
102	  User: { sign_in_github:"PUBLIC", update_profile:"OWN", view_public_profile:"PUBLIC", view_private_profile:"OWN", update_roles:"SYSTEM" },
103	  Announcement: { view_public:"PUBLIC", view_private:"MANAGED_RACE", create:"MANAGED_RACE", edit:"MANAGED_RACE", publish:"MANAGED_RACE", hide:"MANAGED_RACE" },
104	  ScreenDisplay: { view_public_display:"PUBLIC", configure:"MANAGED_RACE", switch_mode:"MANAGED_RACE", fallback:"MANAGED_RACE" },
105	};
106	
107	function getRequiredScope(resourceType: string, action: string): ScopeReq {
108	  return MATRIX[resourceType]?.[action] ?? "SYSTEM";
109	}
110

